CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

CREATE TABLE IF NOT EXISTS roles (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT UNIQUE NOT NULL, description TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), email TEXT UNIQUE NOT NULL, full_name TEXT NOT NULL, hashed_password TEXT, oauth_provider TEXT, role_id UUID REFERENCES roles(id), preferred_language TEXT NOT NULL DEFAULT 'en', is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS matches (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), home_team TEXT NOT NULL, away_team TEXT NOT NULL, venue TEXT NOT NULL, starts_at TIMESTAMP NOT NULL, status TEXT NOT NULL DEFAULT 'scheduled');
CREATE TABLE IF NOT EXISTS gates (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), code TEXT UNIQUE NOT NULL, name TEXT NOT NULL, latitude DOUBLE PRECISION NOT NULL, longitude DOUBLE PRECISION NOT NULL, accessibility BOOLEAN NOT NULL DEFAULT TRUE, current_wait_minutes INT NOT NULL DEFAULT 0, congestion_score DOUBLE PRECISION NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS seats (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), section TEXT NOT NULL, row TEXT NOT NULL, number TEXT NOT NULL, nearest_gate_id UUID REFERENCES gates(id), accessible BOOLEAN NOT NULL DEFAULT FALSE, UNIQUE(section,row,number));
CREATE TABLE IF NOT EXISTS tickets (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID REFERENCES users(id), match_id UUID REFERENCES matches(id), seat_id UUID REFERENCES seats(id), qr_token TEXT UNIQUE NOT NULL);
CREATE TABLE IF NOT EXISTS parking (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT NOT NULL, total_spaces INT NOT NULL, free_spaces INT NOT NULL, accessible_spaces INT NOT NULL DEFAULT 0, latitude DOUBLE PRECISION NOT NULL, longitude DOUBLE PRECISION NOT NULL);
CREATE TABLE IF NOT EXISTS crowd (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), zone TEXT NOT NULL, density DOUBLE PRECISION NOT NULL, queue_length INT NOT NULL, wait_minutes INT NOT NULL, ingress_rate INT NOT NULL, captured_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS transport (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), mode TEXT NOT NULL, route_name TEXT NOT NULL, eta_minutes INT NOT NULL, crowd_level DOUBLE PRECISION NOT NULL, carbon_grams INT NOT NULL, accessibility BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS incidents (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), type TEXT NOT NULL, zone TEXT NOT NULL, description TEXT NOT NULL, priority TEXT NOT NULL DEFAULT 'medium', status TEXT NOT NULL DEFAULT 'open', ai_summary TEXT NOT NULL DEFAULT '', recommended_actions JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS volunteers (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID UNIQUE REFERENCES users(id), assigned_zone TEXT NOT NULL, shift_starts_at TIMESTAMP NOT NULL, shift_ends_at TIMESTAMP NOT NULL, latitude DOUBLE PRECISION NOT NULL DEFAULT 0, longitude DOUBLE PRECISION NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS tasks (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), volunteer_id UUID REFERENCES volunteers(id), title TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'open', priority TEXT NOT NULL DEFAULT 'normal', due_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS food_courts (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT NOT NULL, zone TEXT NOT NULL, queue_minutes INT NOT NULL, open_stalls INT NOT NULL, vegetarian BOOLEAN NOT NULL DEFAULT TRUE, halal BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS waste (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), zone TEXT NOT NULL, kilograms DOUBLE PRECISION NOT NULL, recycled_percent DOUBLE PRECISION NOT NULL, captured_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS energy (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), zone TEXT NOT NULL, kwh DOUBLE PRECISION NOT NULL, captured_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS water (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), zone TEXT NOT NULL, liters DOUBLE PRECISION NOT NULL, captured_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS notifications (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID REFERENCES users(id), audience TEXT NOT NULL DEFAULT 'all', title TEXT NOT NULL, message TEXT NOT NULL, severity TEXT NOT NULL DEFAULT 'info', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_conversations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID REFERENCES users(id), language TEXT NOT NULL DEFAULT 'en', prompt TEXT NOT NULL, response TEXT NOT NULL, sources JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS audit_logs (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), actor_id UUID REFERENCES users(id), action TEXT NOT NULL, entity TEXT NOT NULL, entity_id TEXT NOT NULL, metadata_json JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
